const post = $input.first().json;
const BASE_URL = 'https://entrepreneursofasia.com';
const postUrl = `${BASE_URL}/blog/${post.slug}`;

const isEventRecap = post.category === 'events' || post.title?.toLowerCase().includes('recap');
const isFounderSpotlight = post.category === 'founders' || post.title?.toLowerCase().includes('spotlight');

let content;
if (isEventRecap) {
  content = `Last night's talk was fire.\n\n${post.excerpt}\n\nFull recap + clips → ${postUrl}\nJoin us Thursday 6PM → ${BASE_URL}`;
} else if (isFounderSpotlight) {
  content = `Founder Spotlight: ${post.title}\n\n${post.excerpt}\n\nRead the full story → ${postUrl}`;
} else {
  content = `${post.title}\n\n${post.excerpt}\n\n→ ${postUrl}`;
}

const mediaUrls = post.cover_image_url ? [post.cover_image_url] : [];

return [{
  json: {
    content,
    hashtags: ['ChiangMai', 'DigitalNomad', 'Entrepreneur', 'ChiangMaiFounders', 'EOA'],
    mediaUrls,
    platforms: ['facebook', 'instagram', 'linkedin', 'twitter'],
    source: 'blog-post-pipeline',
    eventId: post.event_id || null
  }
}];

const result = $input.first().json;
if (!result.success) {
  console.error('[blog-social] Partial failure:', JSON.stringify(result));
}
console.log(`[blog-social] success=${result.successCount} failed=${result.failureCount}`);
return [$input.first()];
